import assert from "node:assert";
import { createPrivateKey, createPublicKey } from "node:crypto";
import fs from "node:fs";
import path from "node:path";
import sshpk from "sshpk";
import type {
    Certificate,
    CertificatePEM,
    DER,
    KeyObject,
    PEM,
    PrivateKey,
    PrivateKeyPEM,
    PublicKey,
    PublicKeyPEM,
} from "../source/common.js";
import { split_der } from "../source/crypto_explore_certificate.js";
import { convertPEMtoDER, identifyPemType, removeTrailingLF, toPem } from "../source/crypto_utils.js";

function _readPemFile(filename: string): PEM {
    assert(typeof filename === "string");
    return removeTrailingLF(fs.readFileSync(filename, "utf-8"));
}

function _readPemOrDerFileAsDER(filename: string): DER {
    if (filename.match(/.*\.der/)) {
        return fs.readFileSync(filename) as Buffer;
    }
    const raw_key: string = _readPemFile(filename);
    return convertPEMtoDER(raw_key);
}

function _countPemCertBlocks(pem: string): number {
    const matches = pem.match(/-----BEGIN CERTIFICATE-----/g);
    return matches ? matches.length : 0;
}

/**
 * Read a DER or PEM certificate from file.
 *
 * **Note:** If the PEM file contains multiple certificate blocks
 * (e.g. a leaf cert + CA chain), only the **first** certificate
 * is returned. Use {@link readCertificateChain} to read all
 * certificates individually.
 *
 * @deprecated Use {@link readCertificateChain} instead, which
 * returns each certificate as a separate DER buffer.
 */
export function readCertificate(filename: string): Certificate {
    if (filename.match(/.*\.der/)) {
        return fs.readFileSync(filename) as Certificate;
    }
    const pem = _readPemFile(filename);
    const count = _countPemCertBlocks(pem);
    if (count > 1) {
        console.warn(
            `[node-opcua-crypto] readCertificate: "${path.basename(filename)}"` +
            ` contains ${count} PEM certificate block(s) but only the first` +
            ` will be used. Use readCertificateChain() to read all certificates.`,
        );
    }
    return convertPEMtoDER(pem) as Certificate;
}

/**
 * Read a PEM or DER certificate file that may contain multiple
 * certificates (e.g. a leaf cert + CA issuer chain) and return
 * each certificate as a separate DER `Buffer`.
 *
 * - For a DER file, returns a single-element array.
 * - For a PEM file with N certificate blocks, returns N elements
 *   in the same order they appear in the file (leaf first).
 */
export function readCertificateChain(filename: string): Certificate[] {
    if (filename.match(/.*\.der/)) {
        return split_der(fs.readFileSync(filename) as Certificate);
    }
    const pem = _readPemFile(filename);
    return _extractAllPemDerCertificates(pem);
}

/**
 * Async version of {@link readCertificateChain}.
 */
export async function readCertificateChainAsync(filename: string): Promise<Certificate[]> {
    const buf = await fs.promises.readFile(filename);
    if (filename.match(/.*\.der/)) {
        return split_der(buf as Certificate);
    }
    const pem = removeTrailingLF(buf.toString("utf-8"));
    return _extractAllPemDerCertificates(pem);
}

/**
 * Extract all CERTIFICATE PEM blocks from a PEM string and
 * return each as a separate DER `Buffer`.
 */
function _extractAllPemDerCertificates(pem: string): Certificate[] {
    const certs: Certificate[] = [];
    const regex = /-----BEGIN CERTIFICATE-----\r?\n([/+=a-zA-Z0-9\r\n]*)\r?\n-----END CERTIFICATE-----/g;
    let match: RegExpExecArray | null;
    match = regex.exec(pem);
    while (match !== null) {
        const base64 = match[1].replace(/\r?\n/g, "");
        const derBuffer = Buffer.from(base64, "base64") as Certificate;
        try {
            const separatedCerts = split_der(derBuffer);
            for (const c of separatedCerts) {
                certs.push(c);
            }
        } catch (_err) {
            // Fallback: push buffer as is if it fails parsing
            certs.push(derBuffer);
        }
        match = regex.exec(pem);
    }
    return certs;
}

/**
 * Async version of {@link readCertificate}.
 * Uses `fs.promises.readFile` so the event loop is not blocked
 * during I/O.
 *
 * **Note:** If the PEM file contains multiple certificate blocks,
 * only the first is returned. Use {@link readCertificateChainAsync}.
 *
 * @deprecated Use {@link readCertificateChainAsync} instead.
 */
export async function readCertificateAsync(filename: string): Promise<Certificate> {
    const buf = await fs.promises.readFile(filename);
    if (filename.match(/.*\.der/)) {
        return buf as Certificate;
    }
    const raw_key = removeTrailingLF(buf.toString("utf-8"));
    const count = _countPemCertBlocks(raw_key);
    if (count > 1) {
        console.warn(
            `[node-opcua-crypto] readCertificateAsync: "${path.basename(filename)}"` +
            ` contains ${count} PEM certificate block(s) but only the first` +
            ` will be used. Use readCertificateChainAsync() to read all certificates.`,
        );
    }
    return convertPEMtoDER(raw_key) as Certificate;
}

/**
 * read a DER or PEM certificate from file
 */
export function readPublicKey(filename: string): KeyObject {
    if (filename.match(/.*\.der/)) {
        const der = fs.readFileSync(filename) as Buffer;
        return createPublicKey(der);
    } else {
        const raw_key: string = _readPemFile(filename);
        return createPublicKey(raw_key);
    }
}

/**
 * Async version of {@link readPublicKey}.
 */
export async function readPublicKeyAsync(filename: string): Promise<KeyObject> {
    const buf = await fs.promises.readFile(filename);
    if (filename.match(/.*\.der/)) {
        return createPublicKey(buf);
    }
    return createPublicKey(removeTrailingLF(buf.toString("utf-8")));
}

// console.log("createPrivateKey", (crypto as any).createPrivateKey, process.env.NO_CREATE_PRIVATEKEY);

function myCreatePrivateKey(rawKey: string | Buffer): PrivateKey {
    if (!createPrivateKey || process.env.NO_CREATE_PRIVATEKEY) {
        // we are not running nodejs or createPrivateKey is not supported in the environment
        if (Buffer.isBuffer(rawKey)) {
            const pemKey = toPem(rawKey, "PRIVATE KEY");
            assert(["RSA PRIVATE KEY", "PRIVATE KEY"].indexOf(identifyPemType(pemKey) as string) >= 0);
            return { hidden: pemKey };
        }
        return { hidden: ensureTrailingLF(rawKey as string) };
    }
    // see https://askubuntu.com/questions/1409458/openssl-config-cuases-error-in-node-js-crypto-how-should-the-config-be-updated
    const backup = process.env.OPENSSL_CONF;
    process.env.OPENSSL_CONF = "/dev/null";
    const retValue = createPrivateKey(rawKey);
    process.env.OPENSSL_CONF = backup;
    return { hidden: retValue };
}

function ensureTrailingLF(str: string): string {
    return str.match(/\n$/) ? str : `${str}\n`;
}
/**
 * read a DER or PEM certificate from file
 */
export function readPrivateKey(filename: string): PrivateKey {
    if (filename.match(/.*\.der/)) {
        const der: Buffer = fs.readFileSync(filename);
        return myCreatePrivateKey(der);
    } else {
        const raw_key: string = _readPemFile(filename);
        return myCreatePrivateKey(raw_key);
    }
}

/**
 * Async version of {@link readPrivateKey}.
 */
export async function readPrivateKeyAsync(filename: string): Promise<PrivateKey> {
    const buf = await fs.promises.readFile(filename);
    if (filename.match(/.*\.der/)) {
        return myCreatePrivateKey(buf);
    }
    return myCreatePrivateKey(removeTrailingLF(buf.toString("utf-8")));
}

export function readCertificatePEM(filename: string): CertificatePEM {
    return _readPemFile(filename);
}

/**
 * Async version of {@link readCertificatePEM}.
 */
export async function readCertificatePEMAsync(filename: string): Promise<CertificatePEM> {
    const buf = await fs.promises.readFile(filename, "utf-8");
    return removeTrailingLF(buf);
}

export function readPublicKeyPEM(filename: string): PublicKeyPEM {
    return _readPemFile(filename);
}

/**
 * Async version of {@link readPublicKeyPEM}.
 */
export async function readPublicKeyPEMAsync(filename: string): Promise<PublicKeyPEM> {
    const buf = await fs.promises.readFile(filename, "utf-8");
    return removeTrailingLF(buf);
}
/**
 *
 * @deprecated
 */
export function readPrivateKeyPEM(filename: string): PrivateKeyPEM {
    return _readPemFile(filename);
}

/**
 * Async version of {@link readPrivateKeyPEM}.
 * @deprecated
 */
export async function readPrivateKeyPEMAsync(filename: string): Promise<PrivateKeyPEM> {
    const buf = await fs.promises.readFile(filename, "utf-8");
    return removeTrailingLF(buf);
}

let _g_certificate_store: string = "";

export function setCertificateStore(store: string): string {
    const old_store = _g_certificate_store;
    _g_certificate_store = store;
    return old_store;
}
export function getCertificateStore(): string {
    if (!_g_certificate_store) {
        _g_certificate_store = path.join(__dirname, "../../certificates/");
    }
    return _g_certificate_store;
}
/**
 *
 * @param filename
 */
export function readPrivateRsaKey(filename: string): PrivateKey {
    if (!createPrivateKey) {
        throw new Error("createPrivateKey is not supported in this environment");
    }
    if (filename.substring(0, 1) !== "." && !fs.existsSync(filename)) {
        filename = path.join(getCertificateStore(), filename);
    }
    const content = fs.readFileSync(filename, "utf8");
    const sshKey = sshpk.parsePrivateKey(content, "auto");
    const key = sshKey.toString("pkcs1") as PEM;
    const hidden = createPrivateKey({ format: "pem", type: "pkcs1", key });
    return { hidden };
}

export function readPublicRsaKey(filename: string): PublicKey {
    if (filename.substring(0, 1) !== "." && !fs.existsSync(filename)) {
        filename = path.join(getCertificateStore(), filename);
    }
    const content = fs.readFileSync(filename, "utf-8");
    const sshKey = sshpk.parseKey(content, "ssh");
    const key = sshKey.toString("pkcs1") as PEM;
    return createPublicKey({ format: "pem", type: "pkcs1", key });
}
